### DOMAIN 4: FRONT-END TECHNOLOGIES

#### Angular Fundamentals

**Component Structure:**
```typescript
import { Component, OnInit, Input, Output, EventEmitter } from '@angular/core';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';

@Component({
  selector: 'app-user-form',
  templateUrl: './user-form.component.html',
  styleUrls: ['./user-form.component.css']
})
export class UserFormComponent implements OnInit {

  @Input() userId: number;
  @Output() onSubmit = new EventEmitter<UserDTO>();

  userForm: FormGroup;
  isLoading = false;
  errorMessage: string;

  constructor(
    private fb: FormBuilder,
    private userService: UserService
  ) {}

  ngOnInit(): void {
    this.initializeForm();
    if (this.userId) {
      this.loadUser();
    }
  }

  initializeForm(): void {
    this.userForm = this.fb.group({
      name: ['', [Validators.required, Validators.minLength(3)]],
      email: ['', [Validators.required, Validators.email]],
      status: ['ACTIVE']
    });
  }

  loadUser(): void {
    this.userService.getUser(this.userId).subscribe(
      (user) => {
        this.userForm.patchValue(user);
      },
      (error) => {
        this.errorMessage = 'Failed to load user';
      }
    );
  }

  submit(): void {
    if (this.userForm.invalid) {
      return;
    }

    this.isLoading = true;
    this.userService.saveUser(this.userForm.value).subscribe(
      (result) => {
        this.onSubmit.emit(result);
        this.isLoading = false;
      },
      (error) => {
        this.errorMessage = error.message;
        this.isLoading = false;
      }
    );
  }
}
```

**Service with RxJS Observables:**
```typescript
@Injectable({ providedIn: 'root' })
export class UserService {

  private apiUrl = '/api/users';

  constructor(private http: HttpClient) {}

  getUser(id: number): Observable<UserDTO> {
    return this.http.get<UserDTO>(`${this.apiUrl}/${id}`).pipe(
      tap(user => console.log('Loaded user:', user)),
      catchError(error => {
        console.error('Error loading user', error);
        return throwError(() => new Error('Failed to load user'));
      })
    );
  }

  getAllUsers(): Observable<UserDTO[]> {
    return this.http.get<UserDTO[]>(this.apiUrl).pipe(
      map(users => users.sort((a, b) => a.name.localeCompare(b.name))),
      shareReplay(1)  // Cache result and share with multiple subscribers
    );
  }

  createUser(user: UserDTO): Observable<UserDTO> {
    return this.http.post<UserDTO>(this.apiUrl, user).pipe(
      tap(() => console.log('User created')),
      catchError(this.handleError)
    );
  }

  updateUser(id: number, user: UserDTO): Observable<UserDTO> {
    return this.http.put<UserDTO>(`${this.apiUrl}/${id}`, user);
  }

  deleteUser(id: number): Observable<void> {
    return this.http.delete<void>(`${this.apiUrl}/${id}`);
  }

  private handleError(error: HttpErrorResponse) {
    let errorMsg = 'An error occurred';
    if (error.error instanceof ErrorEvent) {
      errorMsg = error.error.message;
    } else {
      errorMsg = `Server returned code ${error.status}: ${error.error.message}`;
    }
    return throwError(() => new Error(errorMsg));
  }
}
```

#### React Fundamentals

**Functional Component with Hooks:**
```typescript
import React, { useState, useEffect, useCallback } from 'react';
import axios from 'axios';

interface UserDTO {
  id: number;
  name: string;
  email: string;
  status: string;
}

const UserList: React.FC = () => {
  const [users, setUsers] = useState<UserDTO[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [filter, setFilter] = useState('');

  // Fetch users on component mount
  useEffect(() => {
    fetchUsers();
  }, []);

  const fetchUsers = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      const response = await axios.get<UserDTO[]>('/api/users');
      setUsers(response.data);
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to fetch users');
    } finally {
      setLoading(false);
    }
  }, []);

  const filteredUsers = users.filter(user => 
    user.name.toLowerCase().includes(filter.toLowerCase())
  );

  if (loading) return <div>Loading...</div>;
  if (error) return <div className="error">{error}</div>;

  return (
    <div className="user-list">
      <h2>Users</h2>
      <input
        type="text"
        placeholder="Filter by name"
        value={filter}
        onChange={(e) => setFilter(e.target.value)}
      />
      <table>
        <thead>
          <tr>
            <th>Name</th>
            <th>Email</th>
            <th>Status</th>
          </tr>
        </thead>
        <tbody>
          {filteredUsers.map(user => (
            <tr key={user.id}>
              <td>{user.name}</td>
              <td>{user.email}</td>
              <td>{user.status}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

export default UserList;
```

**State Management with Redux:**
```typescript
// Actions
export const fetchUsers = () => ({
  type: 'FETCH_USERS_REQUEST'
});

export const fetchUsersSuccess = (users: UserDTO[]) => ({
  type: 'FETCH_USERS_SUCCESS',
  payload: users
});

export const fetchUsersError = (error: string) => ({
  type: 'FETCH_USERS_ERROR',
  payload: error
});

// Reducer
interface UserState {
  users: UserDTO[];
  loading: boolean;
  error: string | null;
}

const initialState: UserState = {
  users: [],
  loading: false,
  error: null
};

export function userReducer(state = initialState, action: any): UserState {
  switch (action.type) {
    case 'FETCH_USERS_REQUEST':
      return { ...state, loading: true, error: null };
    case 'FETCH_USERS_SUCCESS':
      return { ...state, users: action.payload, loading: false };
    case 'FETCH_USERS_ERROR':
      return { ...state, loading: false, error: action.payload };
    default:
      return state;
  }
}

// Selector
export const selectUsers = (state: any) => state.users.users;
export const selectLoadingUsers = (state: any) => state.users.loading;
```

