## Q2: React Component Optimization

**A:**

Performance optimization is crucial for large applications.

### 1. React.memo - Prevent Unnecessary Re-renders
```typescript
// Without memo: Re-renders on every parent update
function UserCard({ user, onSelect }) {
  return (
    <div onClick={() => onSelect(user.id)}>
      <h3>{user.name}</h3>
      <p>{user.email}</p>
    </div>
  );
}

// With memo: Only re-renders if props change
const UserCard = React.memo(function UserCard({ user, onSelect }) {
  return (
    <div onClick={() => onSelect(user.id)}>
      <h3>{user.name}</h3>
      <p>{user.email}</p>
    </div>
  );
});

// Custom comparison function
const UserCard = React.memo(
  function UserCard({ user, onSelect }) { /* ... */ },
  (prevProps, nextProps) => {
    // Return true if props are equal (skip render)
    return prevProps.user.id === nextProps.user.id &&
           prevProps.onSelect === nextProps.onSelect;
  }
);
```

### 2. Virtual Scrolling for Large Lists
```typescript
// Install react-window
import { FixedSizeList } from 'react-window';

function UserList({ users }) {
  const Row = ({ index, style }) => (
    <div style={style}>
      {users[index].name} - {users[index].email}
    </div>
  );

  return (
    <FixedSizeList
      height={600}
      itemCount={users.length}
      itemSize={35}
      width="100%"
    >
      {Row}
    </FixedSizeList>
  );
}
```

### 3. Code Splitting with React.lazy
```typescript
// Lazy load component only when needed
const HeavyComponent = React.lazy(() => import('./HeavyComponent'));

function App() {
  return (
    <Suspense fallback={<div>Loading...</div>}>
      <HeavyComponent />
    </Suspense>
  );
}

// With route-based code splitting
const AdminPanel = React.lazy(() => import('./AdminPanel'));
const UserProfile = React.lazy(() => import('./UserProfile'));

function Router() {
  const [page, setPage] = useState('home');

  return (
    <Suspense fallback={<div>Loading page...</div>}>
      {page === 'admin' && <AdminPanel />}
      {page === 'profile' && <UserProfile />}
    </Suspense>
  );
}
```

