// Typed dispatch
type AppDispatch = typeof store.dispatch;

// Typed useSelector/useDispatch
export const useAppSelector: TypedUseSelectorHook<AppState> = useSelector;
export const useAppDispatch: () => AppDispatch = useDispatch;

// Component
function Counter() {
